INSERT INTO `coasters` (`coaster_pk`, `coaster_park_fk`, `coaster_title`, `coaster_model`, `coaster_manufacturer`, `coaster_year`, `coaster_height`, `coaster_length`, `coaster_top_speed`, `coaster_gforce`, `coaster_duration`, `coaster_inversion_count`, `coaster_image_path`, `coaster_is_operational`, `coaster_description`, `coaster_lon`, `coaster_lat`, `coaster_created_at`, `coaster_deleted_at`) VALUES
('042fb564699e4ce2ab2dfb9510a970fb', '9e20abe41ec644db87d70f79a93b5360', 'Colossos - Kampf der Giganten', 'Wooden Coaster (Prefabricated Track)', 'Intamin', 2001, 50.00, 1344.00, 110, 3.80, '02:25', 0, 'https://www.heide-park.de/media/gfnhlglg/colossos-12.jpg', 1, 'Colossos is very different from a traditional wooden roller coaster because it is prefabricated. Instead of trackers cutting, shaping, and laying down the track by hand, the track is laser cut in a factory, achieving a higher degree of precision than could ever be done by hand. The track also is made of more layers of wood that are tightly bonded together instead of being traditionally nailed together by hand.', '53.02329', '9.883403', 1778686977, 0),
('0b6cdae6bf0b4650b3a9088cf92de7b0', '708163ff2b224c2cb365f879b4829d8f', 'Toos-Express', 'Junior Coaster ', 'Vekoma', 2001, 12.00, 320.00, 60, 2.00, '00:52', 0, 'https://images.coasterpedia.net/thumb/9/98/Boomerang_%28Attractiepark_Toverland%29_2009-04_04.jpg/800px-Boomerang_%28Attractiepark_Toverland%29_2009-04_04.jpg.webp', 1, 'Toos-Express is an steel indoor roller coaster located at Attractiepark Toverland in Sevenum, Limburg, Netherlands. It is one of the original attractions that opened with the park itself on 19 May 2001 and was manufactured by Vekoma. The coaster has had many name changes over the years. It was simply known as Achtbaan, Dutch for Roller Coaster, from 2001 until 2003. It was also formally referred to as Junior Coaster on for example safety signage.', '51.396851', '5.986248', 1779138564, 0),
('0cbaadbe65c9430bb4419df90a78068d', '708163ff2b224c2cb365f879b4829d8f', 'Booster Bike', 'Motorbike Coaster', 'Vekoma', 2004, 15.00, 593.00, 73, 2.50, '00:55', 0, 'https://images.coasterpedia.net/thumb/b/b1/Booster_Bike_%28Toverland%29_2014_01.jpg/800px-Booster_Bike_%28Toverland%29_2014_01.jpg.webp', 1, 'Booster Bike is a steel launched motorbike roller coaster located at Attractiepark Toverland in Sevenum, Limburg, Netherlands. It is located in the Magische Vallei (English: Magic Valley) area of the park. The ride was manufactured by Vekoma and opened on 27 July 2004. It was the first Motorbike Coaster installation to be built. A clone of this roller coaster opened in 2006 at Chimelong Paradise in China.', '51.397899', '5.985199', 1779138036, 0),
('0cdcd85239fa472ab284a92555df5a37', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'Colorado Adventure', 'Mine Train (Custom MK-900 M)', 'Vekoma', 1996, 26.00, 1280.00, 50, 3.00, '02:55', 0, 'https://static.phlcdn.de/files/uploads/themenpark/images/sommer/mexico/colorado-adventure/ga-colorado-adventure_02.jpg', 1, 'Colorado Adventure is a steel roller coaster located in Phantasialand in Brühl, North Rhine-Westphalia, Germany. The ride was built by Vekoma and has three tyre propelled lifts instead of chain lifts. Originally five trains were supposed to operate, but only four remain in use to this day. The ride opened on 11 May 1996. Due to noise complaints from residents, later on large parts of the ride were enclosed in a hall and surrounded with noise barriers.', '50.798586', '6.88299', 1779133091, 0),
('0f9ab05c117b48a093eca5b197037f7c', '15e1b1eb4f7d4196b790b37a994baa36', 'Bob', 'Swiss Bob', 'Intamin', 1985, 20.00, 524.00, 60, 1.80, '01:40', 0, 'https://content.presspage.com/uploads/1828/1920_efteling-bobsleebaan.jpg?10000', 0, 'Bob (Bobbaan in Dutch) was a steel bobsled roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. It was a Swiss Bob installation from Intamin. The ride operated from 1985 to 2019. Construction of Bob began in 1984 and was completed in early 1985. The attraction opened on 4 April 1985. The entrance had white walls surrounded by two Swiss flags.', '51.648047', '5.047422', 1778178353, 0),
('0fb9d90b86984730810134fbc911cdd8', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'F.L.Y.', 'Flying Coaster', 'Vekoma', 2020, 21.00, 1236.00, 78, 4.50, '01:30', 2, 'https://www.schwarzwaelder-bote.de/media.media.1fa5f4e6-585d-4bd0-8f2b-16f91eeb7184.16x9_1024.jpg', 1, 'F.L.Y. is a steel launched flying roller coaster located at Phantasialand in Brühl, North Rhine-Westphalia, Germany. It is the first flying roller coaster with a launch, as well as being the longest flying coaster in the world. The queue line is equipped with metal detectors, so guests must not have any loose articles before riding.', '50.80008', '6.879511', 1779133396, 0),
('127dc698e29b4f4382340956b1853f34', '708163ff2b224c2cb365f879b4829d8f', 'Fēnix', 'Wing Coaster', 'Bolliger & Mabillard', 2018, 40.00, 813.00, 95, 5.00, '01:45', 3, 'https://i.redd.it/o62lejve28211.png', 1, 'Fēnix is a steel winged roller coaster located at Attractiepark Toverland in Sevenum, Limburg, Netherlands. It was manufactured by Bolliger & Mabillard and opened in 2018. Fēnix was announced by Attractiepark Toverland in January 2017, with the name and theme being announced on 26 September 2017.', '51.40017', '5.983612', 1779138240, 0),
('1aae279b424f45d3b50e69652f802fc6', 'c142f569cb55470b93ecf368b49d54d5', 'Eurosat - CanCan Coaster', 'Steel Coaster', 'Mack Rides', 1989, 25.50, 922.00, 60, 4.00, '03:18', 0, 'https://upload.wikimedia.org/wikipedia/commons/5/5a/Frontansicht_von_Eurosat_-_CanCan_Coaster.jpg', 1, 'Eurosat - CanCan Coaster is a Mack Rides steel enclosed roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. The ride has been in operation since 1989.', '48.267417', '7.720862', 1778539933, 0),
('1c4779f6b3fe40d28b39ead895d8f09d', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Royal Scotsman', 'Family Coaster', 'Vekoma', 1993, 16.00, 522.00, 50, 2.00, '01:40', 0, 'https://cdn.coaster.cloud/attractions/Wq/en/WqenzNoUrD4DDBWZH3A26Q.jpg?class=large', 1, 'Royal Scotsman is a steel roller coaster at Hansa-Park in Sierksdorf, Schleswig-Holstein, Germany. It is surrounded by Nessie.\r\nThe ride opened in 1993 as Rasender Roland. For the 2020 season, the ride was renamed Royal Scotsman to fit in to the newly redone \'Bezauberndes Britannien\' area.', '54.075661', '10.779507', 1779130343, 0),
('1dd47c0c236b4c7abbffe38ebbc905da', 'c142f569cb55470b93ecf368b49d54d5', 'Pegasus', 'YoungSTAR Coaster', 'Mack Rides', 2006, 13.00, 400.00, 65, 3.00, '02:11', 0, 'https://rcdb.com/aaaxzpa', 1, 'Pegasus is a steel roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. It opened in 2006 as the seventh roller coaster at the park. Built by Mack Rides, it is the first installation of the YoungSTAR Coaster model. The front of the train is a pegasus.', '48.267263', '7.719151', 1778540132, 0),
('1ff4a5b397c24a40b44f1800d2863607', 'c142f569cb55470b93ecf368b49d54d5', 'Arthur', 'Inverted Powered Coaster', 'Mack Rides', 2014, 13.50, 505.00, 31, 1.50, '04:30', 0, 'https://www.europapark.de/sites/default/files/styles/wide/public/media_image/2019-12/arthur_bahn_europa-park-2.jpg?itok=K-VjFEN2', 1, 'Arthur (stylised as ARTHUR) is a steel enclosed inverted spinning dark ride powered coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. It opened in 2014 as part of the ARTHUR - In the Minimoys Kingdom area.', '48.263557', '7.724142', 1778539333, 0),
('20a436514a26494bad434e3ea9ccd59d', '06ce4975b2db4c709c5492d0146b8fc3', 'Goliath', 'Mega Coaster', 'Intamin', 2002, 46.80, 1214.00, 106, 4.70, '01:32', 0, 'https://pictures.captaincoaster.com/1440x1440/5830ebc4-2a55-49e2-b155-f1bab6cd1544.jpeg', 1, 'Goliath is a steel roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands.\r\n\r\nThe roller coaster was designed by Swiss company Intamin in collaboration with Ing.-Büro Stengel GmbH, and assembled by RCS GmbH. It uses similar technology to bigger coasters Millennium Force at Cedar Point and Expedition GeForce at Plopsaland Deutschland, specifically the trains, and cable lift hill.', '52.43984', '5.76081', 1779135444, 0),
('20ad35b9d17c4a619e118d9626011a8f', '708163ff2b224c2cb365f879b4829d8f', 'Maximus\' Blitz Bahn', 'Bobkart', 'Wiegand', 2015, 4.00, 512.00, 45, 2.00, '01:10', 0, 'https://www.looopings.nl/img/foto/25/0709logamsem4.jpg', 0, 'Maximus\' Blitz Bahn is a Bobkart build by German manufacturer Wiegand currently located at Attractiepark Toverland in Sevenum, Limburg, Netherlands.  The park confirmed in September 2025 that the ride would be closing at an undisclosed future date. The ride will close on May 17 2026 and will be replaced with a new attraction.', '51.397535', '5.986366', 1779138416, 0),
('22db2a19ca6f47eebf7907e576a53ba3', '9e20abe41ec644db87d70f79a93b5360', 'Toxic Garden', 'Suspended Looping Coaster', 'Vekoma', 1999, 33.30, 689.00, 80, 4.00, '01:36', 5, 'https://images.coasterpedia.net/a/a7/Limit_%28Heide_Park%29_2003_01.jpg', 1, 'Toxic Garden is a Vekoma inverted roller coaster (SLC) located at Heide Park in Soltau, Lower Saxony, Germany. It opened in 1999.\r\n\r\nThe ride opened in 1999 under the name \"Limit.\" In March 2023, Heide Park announced that Limit would be renamed to \"Toxic Garden\", with new thematic elements and a partial replacement of the track.', '53.026208', '9.881913', 1778687831, 0),
('2e25695b19274298b413d4ab85e3a720', '7cac88c695524ffb9a9382f2ef1cfdb6', 'RC Racer', 'Surfrider', 'Intamin', 2010, 25.00, 82.00, 48, 2.80, '01:53', 0, 'https://images.coasterpedia.net/thumb/a/a3/RC_Racer_%28Walt_Disney_Studios_Park%29_2018_01.jpg/800px-RC_Racer_%28Walt_Disney_Studios_Park%29_2018_01.jpg.webp', 1, 'RC Racer is an Intamin launched shuttle roller coaster located at Disney Adventure World in Marne la Vallée, Île-de-France, France. The track is themed to a toy ramp. Single car. Riders are arranged 4 across in 5 rows, for a total of 20 riders per car. The train is themed to resemble RC, a character from the Toy Story movie franchise.', '48.866836', '2.776448', 1779136791, 0),
('2eeed0e836ed4f7fb85507e504b4b5fc', '9e1320bf3aa5466da14a3f5da15c4cdb', 'Odinexpressen', 'Powered Coaster', 'Mack Rides', 1985, 12.00, 300.00, 60, 3.30, '01:53', 0, 'https://pictures.captaincoaster.com/1440x1440/97bb1e7c-72f0-4688-8f65-556994b95b02.jpeg', 0, 'Odinexpressen was a steel powered coaster previously located at Tivoli Gardens in Copenhagen, Hovedstaden, Denmark. Odinexpressen\'s replacement, Mælkevejen, has an almost identical layout. The main difference between the two rides, apart from theme, is the ride\'s speed. Where Odin reaches 60 km/h at top speed, Mælkevejen only reaches 36 km/h. This makes Mælkevejen the more family friendly ride, despite the same layout.', '55.672493', '12.568077', 1779137780, 0),
('2f9b905bb09e4f2ca9c28ea6e7f2c69c', '35594d87cef94afdb3315d87f15ce60d', 'Saven', 'Family Boomerang', 'Vekoma', 2020, 24.20, 238.00, 60, 2.80, '01:40', 0, 'https://cdn.coaster.cloud/attractions/45/xm/45xmawuWuhwxLrFih9NZvx.jpg?class=large', 1, 'Saven is a steel shuttle roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. Saven is Danish for Saw. Saven was scheduled to open on 2 May 2020, but the coronavirus pandemic caused the opening to be delayed. However, it opened a month later on 5 June 2020.', '57.269557', '9.655277', 1778176731, 0),
('2fff0769168e4463915bd23a4edfd4aa', '06ce4975b2db4c709c5492d0146b8fc3', 'Lost Gravity', 'BigDipper', 'Mack Rides', 2016, 32.00, 680.00, 87, 5.10, '02:23', 2, 'https://pictures.captaincoaster.com/1440x1440/58e89fba-79b9-4934-af29-a2eed0b055ff.jpeg', 1, 'Lost Gravity is a steel roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands. The ride was manufactured by Mack Rides and constructed by RCS GmbH. It opened to the public on 24 March 2016.  Construction began in late 2015 and was completed by the end of January 2016. The design of the trains was revealed on 19 February 2016. A week later, testing of the ride began.', '52.44261', '5.76635', 1779135752, 0),
('3161baaa78934b0fa68e11c47eaf2d55', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Nessie', 'Steel Coaster', 'Schwarzkopf GmbH', 1980, 26.00, 741.00, 79, 3.30, '02:10', 1, 'https://www.hansapark.de/assets/images/b/Nessie_purple-174b2ca3.jpg', 1, 'Nessie is a Schwarzkopf steel roller coaster located at Hansa-Park in Sierksdorf, Schleswig-Holstein, Germany. It was the first roller coaster with a vertical loop to be installed at a German amusement park.[1] From 1980 to 2018, the ride was known as Nessie Superrollercoaster.', '54.075271', '10.779148', 1778688775, 0),
('3357bd5460464b4ba623ece0bfb04f9a', '996424466a444592a408af6bc948aa28', 'Star Wars Hyperspace Mountain', 'Launch Coaster', 'Vekoma', 1995, 32.00, 765.00, 71, 5.00, '02:05', 3, 'https://images.coasterpedia.net/thumb/0/0c/Space_Mountain_Mission_2_%28Disneyland_Paris%29_2012_01.jpg/800px-Space_Mountain_Mission_2_%28Disneyland_Paris%29_2012_01.jpg.webp', 1, 'Star Wars Hyperspace Mountain is a steel launched enclosed roller coaster found at Disneyland Paris in Marne la Vallée, Île-de-France, France. When built in 1995, it was the first full-circuit launch coaster. The ride opened on 1 June 1995 as Space Mountain: De la terre a la lune. ', '48.87377', '2.779977', 1779137573, 0),
('35b56bf76a9a4b01b1b49726f331ffff', '708163ff2b224c2cb365f879b4829d8f', 'Troy', 'Wooden Coaster', 'Great Coasters International', 2007, 31.90, 1077.20, 87, 2.40, '01:50', 0, 'https://images.squarespace-cdn.com/content/v1/5f37a0f9d79e154db617e5d5/20ad6fc9-205e-421e-b4fb-1555cf4b1602/toverland-netherlands-troy-gci-wooden-roller-coaster-j.JPG', 1, 'Troy is a wooden roller coaster located at Attractiepark Toverland, in Sevenum, Limburg, Netherlands. The ride was manufactured by Great Coasters International and opened on 1 July 2007. In 2021, the park began selling old rails left over from re-tracking, as well as chain links and wheels. Troy has many twists and turns, similar to many other Great Coasters International coasters.', '51.39681', '5.982554', 1779138688, 0),
('368a8c0a9e914d6aae272677d9102852', '35594d87cef94afdb3315d87f15ce60d', 'Lynet', 'LSM Launch Coaster', 'Gerstlauer Amusement Rides GmbH', 2008, 20.00, 540.00, 80, 4.50, '01:01', 2, 'https://www.faarupsommerland.dk/media/m3ilaaiw/lynet_2024_web_-7.jpg?rxy=0.6472945891783567,0.5045045045045045&rmode=crop&width=1900&v2&format=webp', 1, 'Lynet (Danish for Lightning) is a steel launched roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. It was manufactured by Gerstlauer. The coaster has 4 cars. Riders are arranged 2 across in 3 rows, for a total of 6 riders per car. Riders are held in by over-the-shoulder harnesses', '57.269347', '9.650538', 1778176343, 0),
('3b660011c56945aa9dbc070fd353b1dd', 'c142f569cb55470b93ecf368b49d54d5', 'Atlantica SuperSplash', 'SuperSplash', 'Mack Rides', 2005, 30.00, 390.00, 80, 4.00, '03:35', 0, 'https://images.coasterpedia.net/thumb/e/e2/Atlantica_SuperSplash_%28Europa_Park%29_2010_01.jpg/800px-Atlantica_SuperSplash_%28Europa_Park%29_2010_01.jpg.webp', 1, 'Atlantica SuperSplash is a Mack Rides water roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. It opened on 19 March 2005. The ride\'s theme is based on Portuguese conquistadors.\r\n\r\nThere are also two other SuperSplash coasters with custom layouts, including Journey to Atlantis at SeaWorld San Antonio in San Antonio, Texas, which opened in 2007.', '48.261643', '7.721094', 1778539440, 0),
('3d3031031f2e4c90be78c6a988eb6cb7', 'badaa75dc86843508d19431e17957bf1', 'Roller Ball', 'Roller Ball - M', 'RES Rides', 2020, 25.50, 117.00, 25, 3.00, '01:40', 0, 'https://www.praterwien.com/uploads/tx_dimpraterv2/_processed_/b/2/csm_IMG_9118_7140e29c31.jpg', 1, 'Roller Ball is a 4th Dimension roller coaster located at Prater in Vienna, Austria. It is owned by the Austrian showmen family Kern & Waldmann.', '48.216774', '16.398681', 1778538564, 0),
('3e39d715e03e40ec8c4688706be981c1', 'badaa75dc86843508d19431e17957bf1', 'Wiener Looping', 'BigDipper', 'Mack Rides', 2025, 31.00, 518.00, 81, 4.20, '01:12', 2, 'https://i.redd.it/qr0xg0l8paqf1.jpeg', 1, 'Wiener Looping is a steel roller coaster built by German firm Mack Rides currently located at Prater in Austria. The coaster opened on May 23, 2025', '48.216289', '16.401256', 1778538820, 0),
('3ea6717bc5f24f7aa51bf01a5d6ca9f6', 'c142f569cb55470b93ecf368b49d54d5', 'Alpenexpress Enzian', 'Powered Coaster', 'Mack Rides', 2024, 6.00, 866.20, 45, 2.00, '01:54', 0, 'https://cdn.coaster.cloud/attractions/RP/BH/RPBHHE7ZnjWpcw5FXgoLa5.jpg?class=large', 1, 'Alpenexpress \"Enzian\" is a steel powered coaster from German firm Mack Rides currently located at Europa-Park in Rust, Baden Wuerttemberg, Germany. It replaced a coaster of the same name, Alpenexpress \"Enzian\".', '48.262114', '7.722644', 1778539233, 0),
('43065c9ade2848728d19baa69c6428f1', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'Taron', 'LSM Launch Coaster', 'Intamin', 2016, 30.00, 1320.00, 117, 4.60, '01:40', 0, 'https://cdn.coaster.cloud/attractions/WM/kw/WMkwyG3EkWVaMo3WZX8Mji.jpg?class=large', 1, 'Taron is a steel launched roller coaster located at Phantasialand in Brühl, North Rhine-Westphalia, Germany. Opened in June 2016, it is a Blitz Coaster by Intamin.\r\nA clone of the ride opened at Sunac Land Chengdu in China in 2021. It is called All Speeds.\r\nTaron holds the record for the most intersecting track points on a launched coaster (58). Taron is situated in the new-for-2016 area Klugheim, in Mystery.', '50.799758', '6.882652', 1779133818, 0),
('46f84c9a2f3d48a9a009224e8f116c8c', '35594d87cef94afdb3315d87f15ce60d', 'Mine-Expressen', 'Junior Coaster ', 'Vekoma', 1992, 13.00, 335.00, 46, 1.50, '01:06', 0, 'https://www.faarupsommerland.dk/media/yufpyxel/mineexpressen_2020_tryk_a-0869.jpg?rmode=crop&width=1900&v2&format=webp', 1, 'Mine Expressen is a steel roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. Mine Expressen is one of Vekoma\'s 335m Roller Skater models. This is the largest model Vekoma offers.', '57.268672', '9.655529', 1778176493, 0),
('472368de9c7e489faade607a4c0451c1', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Schlange von Midgard', 'Family Coaster 200', 'Gerstlauer Amusement Rides GmbH', 2011, 10.00, 200.00, 45, 1.30, '01:20', 0, 'https://rcdb.com/aabzspd', 1, 'Die Schlange von Midgard is a steel roller coaster located at Hansa-Park in Sierksdorf, Schleswig-Holstein, Germany.\r\nThe coaster has a single train with 6 cars. In each car, riders are arranged 2 across in a single row, for a total of 12 riders per train.', '54.07712785710466', '10.781595718734383', 1779130534, 0),
('4dcabdb9d3294062810d6f8db4473e52', '26e4ca9faeb3489eb814188be88a0b28', 'Hyperion', 'Mega Coaster', 'Intamin', 2018, 77.00, 1450.00, 142, 4.80, '02:20', 1, 'https://www.intamin.com/wp-content/uploads/2018/07/intamin-news-slides5.jpg', 1, 'Hyperion is a steel hyper roller coaster located at Energylandia in Zator, Małopolskie, Poland. It was manufactured by Intamin and took the title of tallest and fastest hyper coaster in Europe from Shambhala at PortAventura Park at 249.3 feet tall with a drop at 255.9 feet tall. The ride opened on 14 July 2018. It has the tallest drop of any hyper roller coaster, and the tallest roller coaster of all to have an inversion.', '50.000375', '19.411616', 1779215469, 0),
('4f04527d5d714deb8adbf16c28ce0dd1', '06ce4975b2db4c709c5492d0146b8fc3', 'Condor', 'Suspended Looping Coaster', 'Vekoma', 1994, 31.00, 662.00, 80, 4.60, '02:02', 5, 'https://images.coasterpedia.net/thumb/d/d0/Walibi_Holland_25-7-2021_Condor_Sidewinder.jpg/600px-Walibi_Holland_25-7-2021_Condor_Sidewinder.jpg.webp', 1, 'Condor is a steel inverted roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands. Prior to 2014, the ride was known as El Condor. Opened in May 1994, it was the first ever Vekoma Suspended Looping Coaster. It is one of two roller coasters to have the prototype track layout, the other being T3 at Kentucky Kingdom in the United States.', '52.44019', '5.76146', 1779135028, 0),
('4fb7135143c54fa29c5c56f1377bd721', '15e1b1eb4f7d4196b790b37a994baa36', 'Max & Moritz (Max | Blue)', 'Powered Coaster, Twin', 'Mack Rides', 2020, 6.00, 300.00, 36, 1.80, '02:30', 0, 'https://images.coasterpedia.net/thumb/1/10/Efteling_4-10-2020_Max_Track_2.jpg/540px-Efteling_4-10-2020_Max_Track_2.jpg.webp', 1, 'Max & Moritz is a steel twin powered coaster currently operating at Efteling in the Netherlands. it replaced Bob and opened on 20 June 2020, with passholder peviews starting on 4 June. On 9 October 2018, Efteling announced that Bob would reopen after an extended period of downtime. However, the announcement went on to say that Bob would close permanently in 2019 and a new roller coaster, Max & Moritz, would take its place for 2020.', '51.648047', '5.047422', 1778177717, 0),
('55a728af955248768c17ed477119c789', '9e1320bf3aa5466da14a3f5da15c4cdb', 'Mælkevejen', 'Powered Coaster', 'Mack Rides', 2019, 15.30, 312.50, 36, 2.00, '02:14', 0, 'https://standby.dk/wp-content/uploads/2022/07/tivoli-m%C3%A6lkevejejn-pressefoto.jpg', 1, 'Mælkevejen (Danish for Milky Way) is a steel powered coaster located at Tivoli Gardens in Copenhagen, Sjælland, Denmark. It opened on 28 November 2019.', '55.672493', '12.568077', 1778179627, 0),
('5bf3ad17a20b476cba8f6931c8d82c6c', '9b0511db4f0a43c3b12848d5c42a060b', 'Rabalder', 'Force - Two', 'Zierer', 2009, 9.00, 222.00, 39, 2.00, '01:40', 0, 'https://images.coasterpedia.net/thumb/2/25/Rabalder_%28Liseberg%29_2014_01.jpg/800px-Rabalder_%28Liseberg%29_2014_01.jpg.webp', 1, 'Rabalder is a steel kiddie roller coaster located at Liseberg in Gothenburg, Västra Götaland, Sweden. Rabalder is Swedish for Uproar. It has a single train with 10 cars. In each car, riders are arranged 2 across in a single row, for a total of 20 riders per train.', '57.695282', '11.993557', 1779132293, 0),
('5c31a44fe9ce4af9b945215b28b58f67', 'badaa75dc86843508d19431e17957bf1', 'Maskerade', 'Spinning Coaster', 'Gerstlauer Amusement Rides GmbH', 2015, 10.00, 236.00, 41, 3.80, '02:10', 0, 'https://rcdb.com/aadldoa', 1, 'Maskerade is a steel enclosed spinning roller coaster at Prater in Vienna, Vienna, Austria. Built by Gerstlauer, it opened on 1 May 2015.', '48.214245', '16.401072', 1778538149, 0),
('5df6a920b40241f692c5b6277f3edefb', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Crazy Mine', 'Wilde Maus Classic', 'Maurer Rides GmbH', 1997, 15.00, 370.00, 45, 2.70, '01:32', 0, 'https://images.coasterpedia.net/thumb/c/c9/Crazy_Mine_%28Hansa_Park%29_2010_01.jpg/800px-Crazy_Mine_%28Hansa_Park%29_2010_01.jpg.webp', 1, 'Crazy Mine is a steel wild mouse roller coaster located at Hansa-Park in Sieksdorf, Schleswig-Holstein, Germany. The ride was manufactured by Maurer Rides.\r\n\r\nCrazy Mine is a standard Wilde Maus Classic model from Maurer.', '54.076331', '10.780924', 1778688280, 0),
('64b843de44874d7fa7dd0aa3392a8cfd', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'Crazy Bats', 'Custom MK-900', 'Vekoma', 1988, 11.70, 1303.00, 47, 3.90, '04:00', 0, 'https://i.redd.it/cn3ity5kqn631.jpg', 1, 'Crazy Bats (formerly known as Space Center and Temple of the Night Hawk) is a steel enclosed roller coaster located in Phantasialand in Brühl, North Rhine-Westphalia, Germany. It is the first Custom MK-900 installation from Vekoma and was the longest enclosed coaster in the world until Guardians of the Galaxy: Cosmic Rewind opened in 2022.', '50.800639', '6.877917', 1779133221, 0),
('66279e4742b948138ea39c526dc5cc04', '9b0511db4f0a43c3b12848d5c42a060b', 'Helix', 'Launch Coaster', 'Maurer Rides GmbH', 2014, 41.00, 1381.00, 100, 4.30, '02:10', 7, 'https://images.ctfassets.net/nwbqij9m1jag/5tfbNB5LfmQuXPjsI023xB/c2517afe28c37b38113265303f4363cf/Strawberry_Sweden_Gothenburg_Accommodation_Hotel_family_holiday_attraction_liseberg_theme-park_helix_ride-Original-Landscape_Str', 1, 'Helix is a steel launched terrain roller coaster located at Liseberg in Gothenburg, Västra Götaland, Sweden. It was manufactured by Mack Rides and opened in 2014. In October 2012, Liseberg announced that they would be adding a new attraction for the 2014 season. The park hired Mack Rides to build a multi-launch roller coaster with a terrain layout. It would be codenamed Projekt Helix.', '57.695539', '11.990455', 1779131797, 0),
('66693d1c43754e88879b3913ca2027a4', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Cornwall Coaster', 'Family Coaster ', 'Gerstlauer Amusement Rides GmbH', 2026, 18.00, 570.00, 50, 2.30, '02:00', 0, 'https://www.hansapark.de/files/bilder/Der_Park/Attraktionen/Fahrattraktionen/Cornwall%20Coaster/Cornwall-Coaster-Visualisierung-Landschaft.jpg', 1, 'Hansa Park\'s newest addition for the 2026 season. Located in the parks Beautiful Britain themed area. The coaster launches a total of 7 times - riding backwards 3 times.', '54.07543788287226', '10.779629332706884', 1779538688, 0),
('6733ef46ebaf46d2962cc8d1c208487e', 'c142f569cb55470b93ecf368b49d54d5', 'Euro Mir', 'Spinning Coaster', 'Mack Rides', 1997, 28.30, 980.00, 80, 4.00, '5', 0, 'https://upload.wikimedia.org/wikipedia/commons/2/24/Euro-Mir_in_Europa-Park_Rust.JPG', 1, 'Euro-Mir is a Mack Rides spinning roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. The ride opened on 12 June 1997. It is also the first Spinning Coaster installation from Mack Rides.\r\n\r\nEuro Mir opened on 12 June 1997. It was the first spinning coaster from manufacturing firm Mack Rides. The theming for the ride was done by P&P Projects.\r\n\r\nOn 25 March 2026, the park announced that the ride would close in 2026 and be replaced with a new roller coaster.', '48.264914', '7.71963', 1778539805, 0),
('68074c9d556d416299323719cf46805b', '9e20abe41ec644db87d70f79a93b5360', 'Desert Race', 'Accelerator Coaster', 'Intamin', 2007, 19.00, 650.00, 102, 5.00, '00:49', 0, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSiVUUAKrQ-u23O1ld_7cAJ3H5fkjNc8iLM9w&s', 1, 'Desert Race is an Intamin launched roller coaster located at Heide Park in Soltau, Lower Saxony, Germany. The train launches to 102 km/h in 2.4 seconds.', '53.02177', '9.88087', 1778687095, 0),
('6a5582204bce4bc2816dd8bfa7631a4f', '35594d87cef94afdb3315d87f15ce60d', 'Fønix', 'Wildcat', 'Vekoma', 2022, 40.00, 905.00, 95, 4.10, '01:20', 3, 'https://blokhus.dk/wp-content/uploads/2022/10/Z1A7556-1280x853.jpg', 1, 'Fønix (Danish for Phoenix) is a steel roller coaster currently located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. The ride was manufactured by Vekoma and opened on 9 April 2022. Fønix is the first Wildcat model from Vekoma.', '57.27145148936769', '9.665336642463961', 1778175575, 0),
('6b22dd75936745a1b411651634984263', '996424466a444592a408af6bc948aa28', 'Casey Jr. – le Petit Train du Cirque', 'Powered Coaster', 'Vekoma', 1994, 6.00, 300.00, 27, 1.00, '02:00', 0, 'https://www.magicalholidays.nl/wp-content/uploads/2023/08/Banner-Casey-Junior-Le-petit-Train-du-Cirque.jpg', 1, 'Casey Jr. – le Petit Train du Cirque is a steel powered coaster located at Disneyland Park in Marne la Vallée, Île-de-France, France. Casey Jr. – le Petit Train du Cirque is the first roller coaster to feature On-board Audio, as well as the only powered coaster manufactured by Vekoma.\r\nThe ride is situated over and around Pays des Contes de Fées, crossing that ride multiple times.', '48.875377', '2.774266', 1779137254, 0),
('6d64e611bd3742e9982fa674f5512eff', '9e20abe41ec644db87d70f79a93b5360', 'Big Loop', 'Custom MK-1200', 'Vekoma', 1983, 30.00, 706.00, 63, 4.00, '02:20', 4, 'https://images.coasterpedia.net/thumb/d/d9/Big_Loop_%28Heide_Park%29_train_leaving_loop.jpg/800px-Big_Loop_%28Heide_Park%29_train_leaving_loop.jpg.webp', 1, 'Big Loop opened in 1983. The coaster\'s layout is a mirrored clone of Dragon Fyre in Canada\'s Wonderland.', '53.025392', '9.879749', 1778686293, 0),
('6f422eb4ae1744a9b38c10e5e670cdfd', '9e20abe41ec644db87d70f79a93b5360', 'Bobbahn', 'Bobsled Coaster', 'Mack Rides', 1994, 27.00, 990.00, 53, 2.50, '01:40', 0, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQsyno2no76SgZ-n7qeYKd9QMv2P-gtQCofbA&s', 1, 'Bobbahn is a steel bobsled roller coaster located at Heide Park in Soltau, Lower Saxony, Germany. Prior to 2014, the ride was known as Schweizer Bobbahn.', '53.026774', '9.880138', 1778686761, 0),
('716735c8a6604162b64957b51a5df75e', '15e1b1eb4f7d4196b790b37a994baa36', 'Max & Moritz (Moritz | Green)', 'Powered Coaster, Twin', 'Mack Rides', 2020, 6.00, 300.00, 36, 1.80, '02:30', 0, 'https://images.coasterpedia.net/thumb/2/2e/Efteling_4-10-2020_Moritz_Track.jpg/540px-Efteling_4-10-2020_Moritz_Track.jpg.webp', 1, 'Max & Moritz is a steel twin powered coaster currently operating at Efteling in the Netherlands. it replaced Bob and opened on 20 June 2020, with passholder peviews starting on 4 June. On 9 October 2018, Efteling announced that Bob would reopen after an extended period of downtime. However, the announcement went on to say that Bob would close permanently in 2019 and a new roller coaster, Max & Moritz, would take its place for 2020.', '51.648047', '5.047422', 1778177575, 0),
('724661bc28404aceb17a75646e4f9bd7', 'c142f569cb55470b93ecf368b49d54d5', 'Ba-a-a Express', 'Kiddie Coaster', 'ART Engineering GmbH', 2016, 3.00, 80.00, 20, 1.20, '01:30', 0, 'https://rcdb.com/aaecuje', 1, 'Ba-a-a Express is a steel kiddie roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany.', '48.266713384824726', '7.723431228338119', 1778539575, 0),
('782f796e95e64cf1a90f6fe20695b701', '26e4ca9faeb3489eb814188be88a0b28', 'Choco Chip Creek', 'Custom MK-900', 'Vekoma', 2024, 16.50, 1200.00, 55, 3.00, '03:30', 0, 'https://energylandia.pl/wp-content/uploads/2021/10/Sweet-Valley-25.jpg', 1, 'Choco Chip Creek is a steel roller coaster located at Energylandia in Zator, Małopolskie, Poland. The ride was built by Vekoma.\r\n\r\nThe addition of Choco Chip Creek was announced in October 2021. The coaster was part of a new themed area called Sweet Valley. It opened with Sweet Valley on 27 April 2024.', '50.000142', '19.402729', 1779214368, 0),
('7a7a3e8af3e44877b97dc0fba0b4157e', 'badaa75dc86843508d19431e17957bf1', 'Dizzy Mouse', 'Spinning Coaster', 'Reverchon', 1998, 13.00, 420.00, 45, 3.30, '01:01', 0, 'https://images.coasterpedia.net/thumb/8/86/Dizzy_Mouse_%28Prater%29_2003-04_01.jpg/800px-Dizzy_Mouse_%28Prater%29_2003-04_01.jpg.webp', 1, 'Dizzy Mouse (German: Schwindlig Maus) is a steel spinning wild mouse roller coaster built by French manufacturer Reverchon currently located at Prater in Vienna, Vienna, Austria.', '48.216716', '16.396555', 1778537704, 0),
('7aa0511c523c44299844e817f06d0534', '06ce4975b2db4c709c5492d0146b8fc3', 'YOY', 'Raptor Track Twin', 'Rocky Mountain Construction', 2025, 29.00, 655.00, 80, 4.90, '01:30', 6, 'https://rockymtnconstruction.com/wp-content/uploads/2023/09/File-5-scaled-e1744125889545.jpg', 1, 'YOY is a steel single rail roller coaster built by Rocky Mountain Construction at Walibi Holland in the Netherlands. The coaster has two separate tracks: a more intense track with multiple inversions named Thrill, and a more family-friendly track without inversions named Chill. Both tracks opened on 5 April 2025. In February 2023, the coaster was announced as a dual coaster with an inverting side and a non-inverting side. ', '52.43938', '5.762493', 1779136317, 0),
('7e32163df7df4e9691484adf878cc3cb', '26e4ca9faeb3489eb814188be88a0b28', 'Abyssus', 'Shockwave Launch', 'Vekoma', 2021, 38.50, 1316.00, 100, 5.00, '02:00', 4, 'https://cdn.coaster.cloud/attractions/Kj/wx/Kjwx39NUiqbf6Afh7fwvVS.jpg?class=large', 1, 'Abyssus is a steel launched roller coaster at Energylandia in Zator, Małopolskie, Poland. It opened on 14 July 2021 as part of the new Aqualantis expansion. Abyssus is a Shockwave 1320m installation from Vekoma. It has two launches as opposed to only one on the smaller Shockwave product. The ride is part of a new-for-2021 expansion called Aqualantis at Energylandia.', '49.999934', '19.400365', 1779214147, 0),
('7f8f98492b9c44e78e2a84d9b947897e', '15e1b1eb4f7d4196b790b37a994baa36', 'Vliegende Hollander', 'Steel Coaster', 'KumbaK', 2007, 22.50, 420.00, 70, 3.00, '03:45', 0, 'https://www.efteling.com/en/-/media/images/nieuw-park/park/attractions/vliegende-hollander/1024x576-vliegende-hollander-water-overzicht.jpg?h=270&w=500&hash=7A5A81A543592B62EF1E884CD8979394', 1, 'De Vliegende Hollander is a steel water roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. On June 9, 2006, due to a problem with the chain lift hill, a car rolled back, damaging the boat, track and the anti-rollback mechanism. It was determined that the entrance to the 45 degree lift hill had to be altered. The park brought in Intamin to complete this.', '51.647625', '5.051969', 1778178150, 0),
('80afaa5a2a1340139525e513c748050a', '06ce4975b2db4c709c5492d0146b8fc3', 'Speed of Sound', 'Boomerang', 'Vekoma', 2000, 35.50, 285.00, 76, 5.20, '01:48', 3, 'https://images.coasterpedia.net/thumb/1/18/Speed_of_Sound_%28Walibi_Holland%29_2011_01.jpg/800px-Speed_of_Sound_%28Walibi_Holland%29_2011_01.jpg.webp', 1, 'Speed of Sound (formerly known as La Via Volta) is a steel shuttle roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands. The ride also has a soundtrack, \"Thrill Ride\" by DJ Randy van der Velde ft. Jurab.\r\n\r\nSpeed of Sound was one of four roller coasters that opened at the park in 2000. In June 2007, La Via Volta was closed. Four years later in 2011, it was renovated into Speed of Sound. The original Vekoma train was replaced with a new one with on-board audio.', '52.44067', '5.76816', 1779135624, 0),
('80b631fe5d8a4442a063286373c1f2ad', '35594d87cef94afdb3315d87f15ce60d', 'Pindsvinet', 'Family Coaster ', 'Zamperla', 2012, 4.00, 80.00, 14, 1.20, '01:10', 0, 'https://cdn.coaster.cloud/attractions/2E/uR/2EuRKKBAZs4KuxN4ztqvix.jpg?class=large', 1, 'Pindsvinet is a steel kiddie roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. Pindsvinet is Danish for Hedgehog. Single train with 6 cars. In each car, riders are arranged 2 across in a single row, for a total of 12 riders per train.', '57.271035', '9.648012', 1778176588, 0),
('8388dcad04b84878bbdc67888bcae3e0', '15e1b1eb4f7d4196b790b37a994baa36', 'Python', 'MK-1200', 'Vekoma', 1981, 29.00, 749.80, 75, 3.50, '02:08', 4, 'https://images.coasterpedia.net/thumb/1/17/Python_Corkscrew_Efteling.jpg/800px-Python_Corkscrew_Efteling.jpg.webp', 1, 'Python is a steel roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. It was built by Vekoma and opened on April 12, 1981. When it first opened, it was the largest steel coaster in mainland Europe. It was the start of a new strategy of development for the park: moving from a fairy-tale forest into a proper amusement park.', '51.646831', '5.053558', 1778178009, 0),
('838f6f5d99b4475f91e4ee6b549ee724', 'c142f569cb55470b93ecf368b49d54d5', 'Blue fire Megacoaster', 'Launch Coaster', 'Mack Rides', 2009, 38.00, 1056.00, 100, 3.80, '02:20', 4, 'https://images.coasterpedia.net/thumb/c/c3/Blue_Fire_Megacoaster.JPG/800px-Blue_Fire_Megacoaster.JPG.webp', 1, 'Blue fire Megacoaster is a steel launched roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. The ride was built by Mack Rides and opened on 4 April 2009. It is the first coaster at the park with inversions. Blue fire Megacoaster is also a prototype Mack Rides Launch Coaster.', '48.262079', '7.718988', 1778539701, 0),
('839765abfce84f14b88ac5d3f9e8d5d7', '9e1320bf3aa5466da14a3f5da15c4cdb', 'Dæmonen', 'Floorless Coaster', 'Bolliger & Mabillard', 2004, 28.00, 564.00, 77, 4.00, '01:46', 3, 'https://cdn.tivoli.dk/media/xxddfv35/daemonen-tivoli-sommer-2024-11111866.jpg?height=2880&width=3840&format=jpeg', 1, 'Dæmonen is a steel roller coaster located at Tivoli Gardens in Copenhagen, Sjælland, Denmark. It is a Floorless Coaster installation from Bolliger & Mabillard. Dæmonen is Danish for Demon. The coaster operates with 2 trains with 6 cars per train. In each car, riders are arranged 4 across in a single row, for a total of 24 riders per train.', '55.672742', '12.570202', 1778178782, 0),
('85464bace1f748999f5b265acc02f3fd', 'c142f569cb55470b93ecf368b49d54d5', 'Silver Star', 'Hyper Coaster', 'Bolliger & Mabillard', 2002, 73.00, 1620.00, 127, 4.00, '03:00', 0, 'https://www.europapark.de/sites/default/files/styles/wide/public/media_image/2023-08/EP23_Frankreich_Silverstar_Sommer_5.jpg?itok=Rm8W0GoF', 1, 'Silver Star is a steel hyper roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. Opened in 2002, it is currently the fourth tallest roller coaster in Europe (after Red Force, Hyperion and Shambhala), drew with Der Schwur des Kärnan, and was the tallest roller coaster built by Bolliger & Mabillard before Leviathan at Canada\'s Wonderland opened in 2012.[1] The attraction was also the first roller coaster in Europa-Park that was not built by Mack Rides.', '48.267843', '7.72003', 1778540432, 0),
('8571aeea51ee4f5d9db562d1f87f799d', '15e1b1eb4f7d4196b790b37a994baa36', 'Vogel Rok', 'Custom MK-900', 'Vekoma', 1998, 20.00, 643.00, 65, 3.20, '01:36', 0, 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8d/Efteling%2C_Vogelrok_-_panoramio.jpg/1280px-Efteling%2C_Vogelrok_-_panoramio.jpg', 1, 'Vogel Rok marks the first time Efteling tried to combine the excessive theming they are known for with a roller coaster. Originally, a expansion of the Python coaster was planned, but got scrapped due to budget reasons. Later, a duplicate of Europa-Park\'s Eurosat was considered for this location, but MACK Rides could not deliver the ride on time.', '51.65205', '5.052496', 1778177045, 0),
('85864068741e4518b0621e8b338c9e97', '9e20abe41ec644db87d70f79a93b5360', 'Grottenblitz', 'Powered Coaster', 'Mack Rides', 1985, 6.00, 370.00, 45, 2.30, '01:48', 0, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQVInOBfk294OQs1W57emUGKd_UV715u0ZO4A&s', 1, 'Grottenblitz is a steel powered coaster currently located at Heide Park Resort in Soltau, Lower Saxony, Germany.\r\n\r\nThe ride\'s layout is an almost exact copy of Alpenexpress \"Enzian\" at Europa-Park, but it only features small differences, mainly at the end of the ride. Intrestingly enough, both rides feature a themed cave around the second helix.', '53.022988', '9.881391', 1778687425, 0),
('85973397e0d849238adbb09f156b243b', '9b0511db4f0a43c3b12848d5c42a060b', 'Valkyria', 'Dive Coaster', 'Bolliger & Mabillard', 2018, 47.00, 750.00, 105, 3.90, '01:30', 3, 'https://www.themeparks-eu.com/images/VALKYRIA%201/Liseberg%203.jpg', 1, 'Valkyria is a steel Dive Coaster located Liseberg in Gothenburg, Västra Götaland, Sweden. Opened in 2018, the ride was manufactured by Bolliger & Mabillard. It was built as part of a mythological-themed regeneration of the area near Balder, which also included a pendulum ride from Intamin named Loke. The addition of Valkyria was announced in the fall of 2016.', '57.693255', '11.995306', 1779132621, 0),
('879c402f240a434da390acdff2cd457b', 'badaa75dc86843508d19431e17957bf1', 'Megablitz', 'Custom MK-700', 'Vekoma', 1994, 19.00, 550.00, 70, 4.50, '01:30', 0, 'https://lh5.googleusercontent.com/proxy/ABHztRYHv8nVt5xAq2JBCH5WrAUybtzU9pV0dcpAStSGe9jpric1aAy5rfw7YT8Vpv08rlIBKV2G24bM4BjreHNlwwsAAHonrPNEQYr_RrGpcUs', 1, 'Megablitz is a steel roller coaster located at Prater in Vienna, Vienna, Austria. Built by Vekoma, it has a unique layout using the MK-700 track system. It opened in 1994 on the spot previously occupied by the Cortina Bob.', '48.216097', '16.401871', 1778538284, 0),
('87dd4ffd8e3a4a40af1aaf47d8eee4bb', '7cac88c695524ffb9a9382f2ef1cfdb6', 'Crush\'s Coaster', 'Spinning Coaster', 'Maurer Rides GmbH', 2007, 13.00, 820.00, 60, 3.60, '01:55', 0, 'https://dlptips.com/wp-content/uploads/Crushs-Coaster-jpg-webp.webp', 1, 'Crush\'s Coaster is a steel spinning enclosed roller coaster at Disney Adventure World in Marne la Vallée, Île-de-France, France. Crush\'s Coaster is similar to Maurer Söhne\'s Xtended SC 2000 design except for the fact that it has some things that the standard model doesn\'t have, like an elongated non-stop loading system in the station akin to that of Maurer\'s Xtended SC 3000 model.', '48.868171', '2.777825', 1779136628, 0),
('88ccc4aba11e40e197dd4934157caa4b', '26e4ca9faeb3489eb814188be88a0b28', 'Zadra', 'Hybrid I-Box Track', 'Rocky Mountain Construction', 2019, 62.80, 1316.00, 121, 4.00, '01:50', 3, 'https://images.coasterpedia.net/thumb/c/cd/Zadra_%28Energylandia%29_2023_01.jpg/800px-Zadra_%28Energylandia%29_2023_01.jpg.webp', 1, 'Zadra is a steel hybrid roller coaster at Energylandia in Zator, Małopolskie, Poland. It is an I-Box Track coaster from Rocky Mountain Construction.\r\n\r\nZadra is the first RMC I-Box Track coaster built from the ground up versus a rebuild of a former wooden roller coaster.', '50.001902', '19.403771', 1779215992, 0),
('8a3ee2a61cfd4917a253810848caab90', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Flucht von Novgorod', 'Euro-Fighter', 'Gerstlauer Amusement Rides GmbH', 2009, 40.00, 750.00, 100, 4.30, '01:50', 1, 'https://www.hansapark.de/files/bilder/Der_Park/Attraktionen/Fahrattraktionen/Fluch%20von%20Novgorod/Flucht-von-Novgorod_2.jpg', 1, 'Flucht von Novgorod (formerly Fluch von Novgorod) is a steel launched roller coaster located at Hansa-Park in Sierksdorf, Schleswig-Holstein, Germany. Opened in April 2009, it is a custom Euro-Fighter from Gerstlauer.', '54.07433075240257', '10.781028528820373', 1778688479, 0),
('8adb8707d3864714aeccdeccfb0d080d', '996424466a444592a408af6bc948aa28', 'Big Thunder Mountain', 'Custom MK-900 M', 'Vekoma', 1992, 22.00, 1205.00, 65, 2.00, '03:56', 0, 'https://media.disneylandparis.com/d4th/en-usd/images/n017798_2050jan01_big-thunder-mountain_16-9_tcm1861-159546.jpg', 1, 'Big Thunder Mountain is a steel roller coaster located at Disneyland Park in Marne la Vallée, Île-de-France, France. Big Thunder Mountain closed in November 2015 for a renovation. It reopened in December 2016 with new special effects.', '48.871284', '2.774557', 1779137079, 0),
('8cd302078ea84c2ca969e54d7ccdc597', 'badaa75dc86843508d19431e17957bf1', 'Insider', 'Spinning Coaster', 'Maurer Rides GmbH', 2013, 11.10, 300.00, 36, 3.30, '01:08', 0, 'https://www.koidls-prater.at/wp-content/uploads/2020/04/insider-rollercoaster-2.jpg', 1, 'Insider is a steel enclosed wild mouse spinning roller coaster located at Prater in Vienna, Vienna, Austria. It was previously located as Spinning Coaster Maihime (Japanese: スピニングコースター舞姫) at Tokyo Dome City.', '48.216629', '16.397579', 1778538046, 0),
('8f4094ee6c1844bbb1ffbbcfab9eb497', 'badaa75dc86843508d19431e17957bf1', 'Gesengte Sau', 'Bobsled Coaster 610', 'Gerstlauer Amusement Rides GmbH', 2020, 24.00, 610.00, 60, 3.00, '02:00', 0, 'https://pictures.captaincoaster.com/1440x1440/gesengte-sau-wiener-prater-6522d365dd9c9.jpg', 1, '\r\n\'Gesengte Sau\' is a German expression for \'Road Hog\'. The expression comes from the world of butchers; when butchering a pig, the butcher first scorches the pig\'s skin with the butcher\'s axe to clear the bristley hair. It could happen that the pig got loose right after this scorching and ran like hell to escape.\r\nThe term came to be used to name fast, wild and uncareful drivers.... like the pig. In literal German, \'Gesengt(e) Sau\' means \'Scorched Pig\'.', '48.215498', '16.398553', 1778537849, 0),
('8fcc0be897074dd68d0d5b137770c887', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Schwur des Kärnan', 'Infinity Coaster', 'Gerstlauer Amusement Rides GmbH', 2015, 73.00, 1235.00, 127, 4.30, '02:20', 0, 'https://www.hansapark.de/assets/images/1/Der-Schwur-des-Kaernan-6-24553e0e.jpg', 1, 'Der Schwur des Kärnan is a steel Infinity roller coaster located at Hansa-Park in Sierksdorf, Schleswig-Holstein, Germany. It is the first hyper roller coaster built by Gerstlauer.\r\n\r\nThe ride opened in 2015. For the 2017 season, the brickwork was added to cover up the concrete tower.', '54.076376', '10.782882', 1779131318, 0),
('93068830e7154a948a12270675b01b3f', '06ce4975b2db4c709c5492d0146b8fc3', 'Eat My Dust', 'Junior Coaster ', 'Zamperla', 2023, 3.00, 200.00, 40, 1.20, '01:08', 0, 'https://themeparkfreaks.eu/wp-content/uploads/2023/09/Untitled-7-2.png', 1, 'Eat My Dust is a Zamperla kiddie roller coaster currently located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands.', '52.440841', '5.760508', 1779135323, 0),
('972484158a4c444cb75b423bc70d5842', 'badaa75dc86843508d19431e17957bf1', 'Olympia Looping', 'Travelling Steel Coaster', 'BHS', 1989, 32.50, 1250.00, 80, 5.20, '01:45', 5, 'https://images.coasterpedia.net/thumb/b/be/Olympia_Looping_%28Wurstelprater%29_1.jpg/800px-Olympia_Looping_%28Wurstelprater%29_1.jpg.webp', 1, 'Olympia Looping is a steel travelling roller coaster with five inversions owned by R. Barth and Sohn KG, the family business of the late manufacturer Rudolf Barth.', '48.21493365935878', '16.400499887637032', 1778538389, 0),
('9835039b30ca461698f85b210bd228ea', '996424466a444592a408af6bc948aa28', 'Indiana Jones et le Temple du Péril', 'Multi Inversion Coaster', 'Intamin', 1993, 18.00, 600.00, 58, 4.00, '01:15', 1, 'https://www.pariscityvision.com/library/image/5516.jpg', 1, 'Indiana Jones et le Temple du Péril (English: Indiana Jones and the Temple of Peril) is a roller coaster attraction at Disneyland Paris. It opened on 30 July 1993. Based on the Indiana Jones films, guests are taken on an adventure riding in a mining train through a lost temple. The attraction was sponsored by Esso. Indiana Jones et le Temple du Péril opened on 30 July 1993, becoming the first Disney roller coaster to have an inversion.', '48.872288', '2.77192', 1779137398, 0),
('99112b3f30834b3b9523fb0d0fc72639', '26e4ca9faeb3489eb814188be88a0b28', 'Speed', 'Water Coaster', 'Intamin', 2018, 50.00, 687.00, 101, 3.00, '03:00', 0, 'https://www.kierunekzator.pl/wp-content/uploads/2022/08/20220624_151715.jpg', 1, 'Speed is steel water roller coaster at Energylandia in Zator, Małopolskie, Poland. Opened in 2018, it is the world\'s tallest (tied with Divertical at Mirabilandia) and fastest water roller coaster.', '49.998573', '19.40901', 1779215634, 0),
('995fe55531474917834bd71a21509c04', '9e20abe41ec644db87d70f79a93b5360', 'Indy-Blitz', 'Force', 'Zierer', 2008, 4.50, 126.00, 30, 1.20, '00:39', 0, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTtXL_1842-AelmxMDfCj4D_1vwkVqyUaU1oQ&s', 1, 'Indy-Blitz is a Zierer Force One kiddie roller coaster located at Heide Park in Soltau, Lower Saxony, Germany.\r\n\r\nIndy-Blitz has a very similar (but not identical) layout to Zamperla\'s Family Gravity Coaster 80STD. Other Force Ones from Zierer follow the same layout, but mirrored. The ride\'s front car is themed as an Aztec/Red Indian.', '53.023162', '9.87763', 1778687566, 0),
('9baff3f9c6784ebf93d3ec602a2ec694', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'Black Mamba', 'Inverted Coater', 'Bolliger & Mabillard', 2006, 26.00, 768.00, 80, 4.00, '02:20', 4, 'https://pictures.captaincoaster.com/1440x1440/e8865fbe-dd88-4a12-a3e9-d2cc8487aeb6.jpg', 1, 'Black Mamba is a steel inverted roller coaster located in Phantasialand in Brühl, North Rhine-Westphalia, Germany. It was manufactured by Bolliger & Mabillard and opened in 2006. Like many modern Bolliger & Mabillard coasters, the track is filled with sand to absorb rattling and to reduce noise. On 23 May 2006, Black Mamba opened exclusively to ticket holders following an auction of 132 tickets to raise money for charity. It opened to the general public on the following day', '50.799079', '6.880585', 1779132923, 0),
('a3ad4b13ea074b6cae46643b572dc7dd', '06ce4975b2db4c709c5492d0146b8fc3', 'Untamed', 'Hybrid I-Box Track', 'Rocky Mountain Construction', 2019, 36.50, 1085.00, 92, 5.60, '01:46', 5, 'https://upload.wikimedia.org/wikipedia/commons/1/1d/Walibi_Holland_Untamed_first_drop.jpg', 1, 'Untamed is a steel hybrid roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands. It is an I-Box Track conversion of the existing Robin Hood wooden roller coaster manufactured by Rocky Mountain Construction which opened on 1 July 2019. On 6 February 2018, Walibi Holland announced on their Facebook page that Robin Hood was to be refurbished into a new experience for 2019.', '52.44263', '5.76154', 1779135911, 0),
('a506df33664e4588bb3e69eabab1499b', '7cac88c695524ffb9a9382f2ef1cfdb6', 'Avengers Assemble: Flight Force', 'LSM Coaster', 'Vekoma', 2002, 24.40, 996.00, 92, 5.00, '01:10', 3, 'https://pictures.captaincoaster.com/1440x1440/ea024444-6e57-45f9-967f-0d9f90c56e0e.jpg', 1, 'Avengers Assemble: Flight Force is a steel launched enclosed roller coaster located at Disney Adventure World in Marne la Vallée, Île-de-France, France. The ride opened on 16 March 2002 as Rock \'n\' Roller Coaster and was themed to rock band Aerosmith. It closed on 1 September 2019 for a complete retheme, and reopened with its new Marvel theming on 20 July 2022 at the same time as the new Avengers Campus.', '48.865074', '2.779736', 1779136934, 0),
('a51b8165eb8d4aea9de96ca19c86536d', '15e1b1eb4f7d4196b790b37a994baa36', 'Joris en de Draak (Water)', 'Wooden Twin', 'Great Coasters International', 2010, 22.10, 787.90, 75, 3.60, '01:50', 0, 'https://www.efteling.com/en/-/media/images/nieuw-park/park/attractions/joris-en-de-draak/1024x576-joris-en-de-draak-2.jpg', 1, 'Joris en de Draak is a wooden racing roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. It replaced the Pegasus and opened in 2010. Pegasus closed in 2009 due to high maintenance costs. Efteling originally had a motorbike coaster in mind as the replacement for Pegasus. Joravision was hired to theme the ride, they came up with a dragon theme, where the coaster would fight an enormous dragon, using lots of special effects.', '51.6468303970', '5.05248375824', 1778177407, 0);
INSERT INTO `coasters` (`coaster_pk`, `coaster_park_fk`, `coaster_title`, `coaster_model`, `coaster_manufacturer`, `coaster_year`, `coaster_height`, `coaster_length`, `coaster_top_speed`, `coaster_gforce`, `coaster_duration`, `coaster_inversion_count`, `coaster_image_path`, `coaster_is_operational`, `coaster_description`, `coaster_lon`, `coaster_lat`, `coaster_created_at`, `coaster_deleted_at`) VALUES
('a91e51bbc73c497fa2f4082a973ca677', '26e4ca9faeb3489eb814188be88a0b28', 'Frida', 'Junior Coaster ', 'Vekoma', 2019, 13.00, 247.00, 45, 2.30, '01:20', 0, 'https://pictures.captaincoaster.com/1440x1440/9cb71e2e-a7fb-4ef5-adfb-9c31fe3dc522.jpg', 1, 'Frida is a steel roller coaster located at Energylandia in Zator, Małopolskie, Poland. It runs with a single train with 8 cars. In each car, riders are arranged 2 across in a single row, for a total of 16 riders per train.\r\n\r\n', '50.001835', '19.400906', 1779215276, 0),
('ab5f5410a722474cbca6900bdd4d0965', '15e1b1eb4f7d4196b790b37a994baa36', 'Pegasus', 'Wooden Coaster', 'Intamin', 1991, 15.00, 492.30, 55, 3.50, '01:43', 0, 'https://preview.redd.it/does-anyone-know-the-name-of-this-train-type-pegasus-pre-v0-y2vgt7wohx0f1.jpg?width=1200&format=pjpg&auto=webp&s=1568f09c8cbe29f78c73bea4af39499e003b9211', 0, 'Pegasus was an Intamin wooden roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. It was replaced by Joris en de Draak in 2010. Pegasus opened on 1 July 1991. The ride closed on 19 June 2009.', '51.646661', '5.052356', 1778178252, 0),
('ab999b0ce5004ad7a1b4f5e71e8a0970', '9e1320bf3aa5466da14a3f5da15c4cdb', 'Rutchebanen', 'Wooden', 'L.A. Thompson Scenic Railway Company', 1914, 12.00, 720.00, 60, 1.70, '02:10', 0, 'https://rcdb.com/aabnlqa', 1, 'Rutschebanen is a wooden roller coaster located at Tivoli Gardens in Copenhagen, Sjælland, Denmark. The roller coaster is the third oldest roller coaster in operation. Rutschebanen in English is \"Roller Coaster\".', '55.673242', '12.566927', 1778179741, 0),
('ae7f7644085940d48ea68b5cb9ec4e64', '9e1320bf3aa5466da14a3f5da15c4cdb', 'Kamelen', 'Force', 'Zierer', 2019, 6.00, 140.00, 24, 1.30, '01:20', 0, 'https://i.ytimg.com/vi/vdKL1yF8X-A/maxresdefault.jpg', 1, 'Kamelen is a steel roller coaster built by German manufacturer Zierer currently located at Tivoli Gardens in Copenhagen, Sjælland, Denmark. The coaster replaced the Karavanen.', '55.673606', '12.570945', 1778178935, 0),
('afed80c146644e5bb0d6b56daba25f57', '9b0511db4f0a43c3b12848d5c42a060b', 'Lisebergbanan', 'Custom - Schwarzkopf', 'Schwarzkopf GmbH', 1987, 45.00, 1340.20, 80, 3.30, '03:10', 0, 'https://www.themeparkarchive.com/Archive/Large/49629.jpg', 1, 'Lisebergbanan (English: Liseberg rail line) is a steel roller coaster located at Gothenburg, Västra Götaland, Sweden. It opened on 18 April 1987, and was a collaboration between Zierer and Schwarzkopf.\r\nWhen Anton Schwarzkopf\'s company went bankrupt in the 1980s, he worked with Zierer to produce several roller coasters. Lisebergbanan was the first of these rides, and has been said to be Schwarzkopf\'s favourite roller coaster.', '57.694833', '11.99275', 1779131942, 0),
('b0da893fdd334c97a3e543e0b0495955', '9b0511db4f0a43c3b12848d5c42a060b', 'Luna', 'Family Boomerang', 'Vekoma', 2023, 33.50, 242.00, 68, 2.00, '02:10', 0, 'https://www.liseberg.se/optimized/720p/7c9326ad/globalassets/attraktioner/luna/luna-bana1920x1080.jpg', 1, 'Luna is a steel shuttle roller coaster located at Liseberg in Gothenburg, Västra Götaland, Sweden. Luna was announced in December 2021 as part of a new themed area called Luna Park.[1]\r\n\r\nIn October 2022, track pieces began to arrive at the park. It opened on 22 April 2023.', '57.69473742615474', '11.992732137341738', 1779132103, 0),
('b1177d8a9525426090b10dd87452bf01', '26e4ca9faeb3489eb814188be88a0b28', 'Circus Coaster', 'Powered Coaster', 'SBF Visa Group', 2017, 1.00, 100.00, 10, 1.00, '01:10', 0, 'https://rcdb.com/aaejipg', 1, 'Circus Coaster is a powered kiddie coaster at Energylandia. The coaster has a single train with 4 cars. In each car, riders are arranged 2 across in 2 rows, for a total of 16 riders per train.', '49.999707', '19.408281', 1779214484, 0),
('b26fad7375f647a29db1d0fc4b5544dd', '35594d87cef94afdb3315d87f15ce60d', 'Oraken', 'Suspended Family Coaster', 'Vekoma', 2013, 19.30, 453.00, 75, 3.50, '01:20', 0, 'https://cdn.coaster.cloud/attractions/QD/38/QD38TnhTrVfufhdRie3Ets.jpg?class=large', 1, 'Orkanen is a steel suspended roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. Orkanen is Danish for Hurricane. 10 cars per train. In each car, riders are arranged 2 across in a single row, for a total of 20 riders per train.', '57.269882', '9.645229', 1778176173, 0),
('ba4ffb6518954a99b0fc7c9f56c40a09', '26e4ca9faeb3489eb814188be88a0b28', 'Dragon Roller Coaster', 'Suspended Family Coaster', 'Vekoma', 2015, 19.30, 453.00, 76, 3.50, '01:30', 0, 'https://www.kierunekzator.pl/wp-content/uploads/2025/02/20220906_141533.jpg', 1, 'Dragon Roller Coaster is a steel suspended roller coaster located at Energylandia in Zator, Małopolskie, Poland. The ride opened in 2015.', '49.999975', '19.406403', 1779214681, 0),
('bbe33e391c86479d8158a85c88fc1b00', '15e1b1eb4f7d4196b790b37a994baa36', 'Baron 1898', 'Dive Coaster', 'Bolliger & Mabillard', 2015, 30.00, 501.00, 90, 4.10, '02:10', 2, 'https://images.coasterpedia.net/thumb/8/8a/Efteling_Baron_overview.jpg/800px-Efteling_Baron_overview.jpg.webp', 1, 'Baron 1898 is a steel floorless diving roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. Opened on 1 July 2015, it is a Dive Coaster installation from Bolliger & Mabillard. It was confirmed in a newspaper interview with park CEO Fons Jurgens that Efteling would open a new Bolliger & Mabillard Dive Coaster in 2015. On 15 October 2014, Efteling announced that the name would be Baron 1898.', '51.6483', '5.050995', 1778177175, 0),
('bcb34a40e007480da32a7ce92c6ec944', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'Raik', 'Family Boomerang', 'Vekoma', 2016, 25.00, 210.00, 62, 2.10, '00:59', 0, 'https://rcdb.com/aaebkda', 1, 'Raik is a steel shuttle roller coaster located at Phantasialand in Brühl, North Rhine-Westphalia, Germany. Raik was added alongside Taron, an Intamin Blitz Coaster as part of Phantasialand\'s new-for-2016 project, Klugheim. It is a custom Family Boomerang from Vekoma.', '50.799573', '6.883449', 1779133657, 0),
('bccce1f2149e445da41ae98683be9ecf', '708163ff2b224c2cb365f879b4829d8f', 'Dwervelwind', 'Spinning Coaster', 'Mack Rides', 2012, 20.00, 500.00, 70, 3.10, '01:52', 0, 'https://images.coasterpedia.net/thumb/1/1b/Dwervelwind_%28Toverland%29_2013_01.jpg/800px-Dwervelwind_%28Toverland%29_2013_01.jpg.webp', 1, 'Dwervelwind is a Mack Rides spinning roller coaster located at Attractiepark Toverland in Sevenum, Limburg, Netherlands. The coaster has 2 trains with 4 cars per train. In each car, riders are arranged 2 across in 2 rows, for a total of 16 riders per train.', '51.399083', '5.985696', 1779138128, 0),
('c02378956a224edcbe6ac80ef2a20f75', '35594d87cef94afdb3315d87f15ce60d', 'Flagermusen', 'Spinning Coaster', 'Reverchon', 2001, 13.00, 420.00, 47, 2.50, '01:30', 0, 'https://www.faarupsommerland.dk/media/z1bgalra/flagermusen-7.jpg?rmode=crop&width=1900&v2&format=webp', 1, 'Flagermusen is a steel spinning wild mouse roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. Flagermusen is Danish for Bat. Single cars. Riders are arranged 4 across in a single row, for a total of 4 riders per car.', '57.270307', '9.652122', 1778176839, 0),
('c2c8114130874c7bb6fd64af63b5a3b2', 'c142f569cb55470b93ecf368b49d54d5', 'Matterhorn Blitz', 'Wilde Maus', 'Mack Rides', 1999, 16.00, 383.00, 60, 2.00, '02:20', 0, 'https://www.europapark.de/sites/default/files/import/attraction/596/Matterhorn-Blitz_Oesterreich_Europa-Park.jpg', 1, 'Matterhorn Blitz is a custom wild mouse roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. Built by Mack Rides, the ride opened on 25 March 1999. Unlike other wild mouse coasters, it features an elevator lift instead of a chain lift hill.', '48.266917', '7.720389', 1778540045, 0),
('c2cd3019d965467385d14abeb0f39d3b', 'c142f569cb55470b93ecf368b49d54d5', 'Poseidon', 'Water Coaster', 'Mack Rides', 2000, 23.00, 836.00, 70, 3.00, '04:00', 0, 'https://upload.wikimedia.org/wikipedia/commons/e/eb/Europapark_Poseidon.jpg', 1, 'Poseidon is a Mack Rides water roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. It opened on 12 July 2000.', '48.26704957985338', '7.719297151620892', 1778540226, 0),
('c44982e4f2284565a4de0223334e6291', '9b0511db4f0a43c3b12848d5c42a060b', 'Balder', 'Wooden Coaster (Prefabricated Track)', 'Intamin', 2003, 36.00, 1070.00, 90, 3.60, '02:24', 0, 'https://www.liseberg.se/optimized/facebook/155bf834/globalassets/attraktioner/balder/balder_forlangd.jpg', 1, 'The addition of Balder was announced in late 2001.\r\nBalder was closed for most of 2022 to allow it to undergo a refurbishment. It reopened in October 2022. The ride is themed around the Scandinavian god of justice of the same name. Balder is the son of the gods Frigg and Odin. He could only be killed by a mistletoe arrow shot by his brother, the blind archer Hoder.', '57.693369', '11.99638', 1779131597, 0),
('cf5f648acb664361bddcb52e01dd1d4a', '06ce4975b2db4c709c5492d0146b8fc3', 'Drako', 'Tivoli', 'Zierer', 1992, 6.00, 199.00, 32, 1.20, '00:54', 0, 'https://images.coasterpedia.net/thumb/b/ba/Drako_%28Walibi_Holland%29_2024_01.jpg/800px-Drako_%28Walibi_Holland%29_2024_01.jpg.webp', 1, 'Drako is a steel kiddie roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands. The ride originally opened in 1987 at Zygo Park in France, and it was named Tarzungle. It lasted until the park\'s closure in 1991. It reopened at Flevohof the following year, being repainted and renamed to Keverbaan, which translates to Beetletrack. It was located in the park\'s kids\' section.', '52.442914', '5.767519', 1779135207, 0),
('d3807986f88d4b1c93dc7955c3bf6e43', '26e4ca9faeb3489eb814188be88a0b28', 'Formuła', 'Space Warp LSM', 'Vekoma', 2016, 24.80, 560.00, 79, 3.80, '01:40', 3, 'https://images.coasterpedia.net/thumb/f/ff/Formu%C5%82aEnergylandia.jpeg/800px-Formu%C5%82aEnergylandia.jpeg.webp', 1, 'Formuła is a steel launched roller coaster located at Energylandia in Zator, Małopolskie, Poland. It was manufactured by Vekoma and opened in 2016 as the company\'s first new generation thrill coaster. Formuła was the first Space Warp model from Vekoma. The ride is a compact launch coaster with 560 metres of track, an LSM launch, and three inversions.', '49.999394', '19.405235', 1779215108, 0),
('dabbe3fd442746cd8443abac13d6279e', '15e1b1eb4f7d4196b790b37a994baa36', 'Joris en de Draak (Fire)', 'Wooden Twin', 'Great Coasters International', 2010, 22.10, 787.90, 75, 3.60, '01:50', 0, 'https://upload.wikimedia.org/wikipedia/commons/4/4d/Joris_en_de_Draak_-_Dragon.JPG', 1, 'Joris en de Draak is a wooden racing roller coaster located at Efteling in Kaatsheuvel, North Brabant, Netherlands. It replaced the Pegasus and opened in 2010. Pegasus closed in 2009 due to high maintenance costs. Efteling originally had a motorbike coaster in mind as the replacement for Pegasus. Joravision was hired to theme the ride, they came up with a dragon theme, where the coaster would fight an enormous dragon, using lots of special effects.', '51.6468303970', '5.05248375824', 1778177423, 0),
('db52fbae726148c7a6388206435b392c', '26e4ca9faeb3489eb814188be88a0b28', 'Boomerang', 'Family Boomerang', 'Vekoma', 2017, 23.00, 208.00, 60, 3.00, '01:36', 0, 'https://rcdb.com/aaelfxf', 1, 'Boomerang is a steel shuttle roller coaster located at Energylandia in Zator, Małopolskie, Poland. It opened on 29 April 2017. The ride has a tunnel, and travels backwards.', '50.001462', '19.408106', 1779214250, 0),
('dbd52ca0cd2a443db50770af8b25e2cf', '9e20abe41ec644db87d70f79a93b5360', 'Krake', 'Dive Coaster', 'Bolliger & Mabillard', 2011, 41.00, 476.00, 103, 3.80, '01:10', 1, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRpGlwHapND24HyMtTDDl88ORcTDT_C0p1whw&s', 1, 'Krake (German for Octopus) is a steel roller coaster located at Heide Park in Soltau, Lower Saxony, Germany. Opened on 16 April 2011, it is a custom Dive Coaster installation from Bolliger & Mabillard.\r\n\r\nAs the name implies, Krake is themed around a large Kraken that swallows the riders when they descend the vertical drop. A near miss element themed as a large octopus, featured in the advertising for the attraction, was added for the 2012 season.', '53.024999', '9.877926', 1778687705, 0),
('dfbfeb8c425e4ac3a449e1defc6b4239', 'badaa75dc86843508d19431e17957bf1', 'Boomerang', 'Boomerang', 'Vekoma', 1992, 35.50, 285.00, 76, 5.20, '01:48', 3, 'https://images.coasterpedia.net/thumb/1/15/Boomerang_%28Prater%29_2008-08-27_01.jpg/800px-Boomerang_%28Prater%29_2008-08-27_01.jpg.webp', 1, 'Boomerang is a steel shuttle roller coaster located at Prater in Vienna, Vienna, Austria. It is best known for being the first of two Vekoma Boomerang installations to not use shoulder straps.', '48.21535', '16.40111', 1778537550, 0),
('e07f70121b434ba18ca7790a9fec4799', '9b0511db4f0a43c3b12848d5c42a060b', 'Stampbanan', 'Mini Coaster', 'Preston & Barbieri', 2013, 3.30, 53.80, 20, 1.20, '01:10', 0, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTyzGIjK4L19IoG08RWb9RNlyG0Nlhm1zJm-g&s', 1, 'Stampbanan is a steel kiddie roller coaster located at Liseberg in Gothenburg, Västra Götaland, Sweden. It has a ingle train with 6 cars. In each car, riders are arranged 2 across in a single row, for a total of 12 riders per train. The lead car has two rows, allowing for a capacity of 14 riders.', '57.695862', '11.993783', 1779132498, 0),
('e48afef6762b42f29b1db3a68ef99b65', 'c142f569cb55470b93ecf368b49d54d5', 'Schweizer Bobbahn', 'Bobsled Coaster', 'Mack Rides', 1985, 20.00, 487.00, 50, 3.00, '02:05', 0, 'https://www.europapark.de/sites/default/files/import/attraction/604/SchweizerBobbahn_Schweiz_Europa-Park.jpg', 1, 'Schweizer Bobbahn is a Mack Rides bobsled roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. The ride opened in 1985.', '48.266314', '7.72158', 1778540330, 0),
('e73399d1d40a4ee79bb3502c125c15db', 'd42cbe63a7654bba96a7b0bea106f4b4', 'Kleine Zar', 'Mini Coaster', 'Preston & Baribieri', 2017, 3.30, 53.80, 20, 1.30, '00:50', 0, 'https://www.hansapark.de/files/bilder/Der_Park/Attraktionen/Fahrattraktionen/Der%20kleine%20Zar/Der-kleine-Zar-2.jpg', 1, 'Der Kleine Zar (The Little Tsar) is a steel kiddie roller coaster located at Hansa-Park in Sierksdorf, Schleswig-Holstein, Germany.\r\n\r\nThe ride was first mentioned in October 2015 and slated for opening in 2016. The name \"Der Kleine Zar\" was later revealed. It did not open in 2016 as planned due to delays in the TÜV certification process. Following a successfull certification, the attraction opened on 7 April 2017.', '54.07484807625578', '10.780898519032426', 1778688642, 0),
('e923e0e56ad74a8bbc6976b2c256877f', '06ce4975b2db4c709c5492d0146b8fc3', 'Xpress: Platform 13', 'LSM Coaster', 'Vekoma', 2000, 25.80, 996.00, 90, 5.00, '01:15', 3, 'https://www.walibi.nl/adobe/dynamicmedia/deliver/dm-aid--b79a4327-1d0b-4e60-b2b5-9c88600abba7/attracties-xpress-4.jpg?quality=85&preferwebp=true', 1, 'Xpress: Platform 13 is a steel launched roller coaster located at Walibi Holland in Biddinghuizen, Flevoland, Netherlands. Built by Vekoma, it opened in April 2000 as part of a large expansion of the park into Six Flags Holland. Originally, the ride was planned to be named Riddler\'s Revenge since the track was painted green at the Vekoma factory. Before the ride was installed, plans changed, and it was repainted with red track and blue supports and renamed Superman The Ride.', '52.43986', '5.76514', 1779136085, 0),
('ebbe5c286b8b404c9fb1f6892f3c4f36', '35594d87cef94afdb3315d87f15ce60d', 'Falken', 'Wooden', 'S&S Sensei Technologies', 2004, 20.00, 622.00, 75, 3.30, '01:54', 0, 'https://www.faarupsommerland.dk/media/ktupqtw1/falken2018.jpg?rxy=0.7244488977955912,0.43993993993993996&rmode=crop&width=1900&v2&format=webp', 1, 'Falken is a wooden roller coaster located at Fårup Sommerland in Blokhus, Nordjylland, Denmark. Falken is Danish for The Falcon. The attraction opened in May 2004. Its track and supports were engineered by Ride Centerline. Single train with 5 cars. In each car, riders are arranged 2 across in 3 rows, for a total of 30 riders per train. The train was built by Gerstlauer.', '57.269967907157756', '9.645752054392826', 1778175845, 0),
('ec72a00932b54b0f82c6759c8c53ba00', '26e4ca9faeb3489eb814188be88a0b28', 'Draken', 'Mini Coaster', 'Preston & Barbieri', 2017, 3.30, 140.00, 35, 1.30, '00:50', 0, 'https://images.coasterpedia.net/thumb/7/76/Draken_%28Energylandia%29_2023_01.jpg/800px-Draken_%28Energylandia%29_2023_01.jpg.webp', 1, 'Draken is a steel sit-down roller coaster located at Energylandia in Zator, Małopolskie, Poland. The ride opened in 2017.', '50.001756', '19.402089', 1779214907, 0),
('ec8c0503c11c4b91a009b896aa426697', 'c142f569cb55470b93ecf368b49d54d5', 'Voltron Nevera', 'Stryker Coaster', 'Mack Rides GmbH & Co KG', 2024, 32.50, 1385.00, 100, 0.00, '03:00', 7, 'https://cdn.coaster.cloud/attractions/L8/p7/L8p7aSsb73mQ6ZRTTMLWiL.jpg?class=large', 1, 'Voltron Nevera is a steel launched semi-floorless roller coaster currently operating at Europa-Park in Rust, Baden-Württemberg, Germany.', '48.265785', '7.720206', 1778177045, 0),
('ed517cfb1f84423ab2de2648acf3703c', 'f07a7ebb0f6d42b6b61741dc16b426fd', 'Winja\'s Fear & Force', 'Spinning Coaster', 'Maurer Rides GmbH', 2002, 17.40, 465.00, 66, 3.00, '01:10', 0, 'https://static.phlcdn.de/files/uploads/themenpark/images/sommer/fantasy/winjas-fear-force/ga-winjas-fear-force_03.jpg', 1, 'Winja\'s Fear & Force is a spinning wild mouse twin indoor roller coasters located at Phantasialand in Brühl, North Rhine-Westphalia, Germany. They are situated in Wuze Town, an indoor area of the park. The rides were built by Maurer Rides. The ride has two tracks, which mirror each other, but also feature some unique sections.', '50.800102', '6.877633', 1779134042, 0),
('efe4cf3b00c94d34acd6773cc2481813', 'c142f569cb55470b93ecf368b49d54d5', 'Wodan Timbur Coaster', 'Wooden Coaster', 'Great Coasters International', 2012, 40.00, 1050.00, 100, 3.50, '03:25', 0, 'https://upload.wikimedia.org/wikipedia/commons/1/1a/Europa-Park_-_Wodan_-_Timburcoaster_%2817%29.JPG', 1, 'Wodan Timbur coaster is a wooden roller coaster located at Europa-Park in Rust, Baden Wuerttemberg, Germany. It opened on 31 March 2012 and was built by Great Coasters International.[1]\r\n\r\nThe ride is located in the Iceland section of the park, which opened in 2009. It is the park\'s first and only wooden coaster. Plus, the attraction features a restroom halfway throughout the queue line.', '48.261239', '7.71897', 1778540746, 0),
('f2b0df34f96b4e6eabba31b27207fb0a', '9e20abe41ec644db87d70f79a93b5360', 'Flug der Dämonen', 'Wing Coaster', 'Bolliger & Mabillard', 2014, 40.00, 772.00, 100, 4.10, '03:00', 5, 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT60ZDfn2a7JdCZA9M_zH8o43JEa5YyU3NZ4A&s', 1, 'Flug der Dämonen is a steel winged roller coaster located at Heide Park in Soltau, Lower Saxony, Germany. It is a Bolliger & Mabillard Wing Coaster installed by RCS GmbH. On 18 August 2013, details were revealed on the size of the ride and number of inversions. The ride opened on 29 March 2014.', '53.025875', '9.879648', 1778687237, 0),
('f49bc166263d483a889f151a10adb6e2', '26e4ca9faeb3489eb814188be88a0b28', 'Energuś Roller Coaster', 'Junior Coaster ', 'Vekoma', 2015, 13.00, 335.00, 46, 2.00, '01:30', 0, 'https://energylandia.pl/wp-content/uploads/2017/03/3-2.jpg', 1, 'Energuś Roller Coaster is a steel roller coaster located at Energylandia in Zator, Małopolskie, Poland. Energuś Roller Coaster is one of Vekoma\'s 335m Roller Skater installations. This is the largest Junior Coaster version Vekoma offers.', '50.000214', '19.41048', 1779215018, 0);

